    "html": "<div style=\"position:absolute; inset:0.42in; border:1px solid #E4D9C2; pointer-events:none;\"></div>\n  <div style=\"position:absolute; inset:0; padding:0.85in 0.85in 0.62in;\">\n    <div style=\"display:flex; align-items:flex-end; justify-content:space-between; border-bottom:1.5px solid #2C2722; padding-bottom:10px; margin-bottom:30px;\">\n      <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:26px; margin:0;\">목차</h2>\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; color:#B0492C; font-size:15px;\">Contents</span>\n    </div>\n    <div>\n      <div data-toc=\"vow\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">서약문</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"prayer\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">기도 제목</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"travel\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">여정 한눈에 보기 (항공·숙소)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"overview\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">전체 일정 개요</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"grid\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">사역 전체 일정표</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"schedule\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">상세 일정 (일자별)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"roster\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">참석자 명단</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"checklist\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">선교 준비 체크리스트</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"contacts\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">숙소 · 비상 연락망</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"guide\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">과테말라 가이드 · 문화</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"weather\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">현지 날씨 (6/30–7/6)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"culture\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">문화탐방 · 안티구아</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"spanish\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">스페인어 필수 회화</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"qt\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">묵상과 다이어리 (Q.T)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"songs\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">찬양 악보</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"mk_program\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">MK 프로그램 · 프로필</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n    </div>"
