    "html": "<div style=\"position:absolute; inset:0; padding:0.85in 0.85in 0.62in; display:flex; flex-direction:column;\">\n    <div style=\"display:flex; align-items:flex-end; justify-content:space-between; border-bottom:1.5px solid #2C2722; padding-bottom:10px; margin-bottom:18px;\">\n      <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:26px; margin:0;\">호텔 시설 안내 · 2층</h2>\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; color:#B0492C; font-size:15px;\">Segundo Nivel</span>\n    </div>\n    <div style=\"flex:1; position:relative; min-height:0;\">\n      <img src=\"assets/extra/hotel_level2.jpg\" alt=\"바르셀로 과테말라시티 2층 안내도\" style=\"position:absolute; inset:0; width:100%; height:100%; object-fit:contain;\"/>\n    </div>"
