    "html": "<div style=\"position:absolute; inset:0.42in; border:1px solid #E4D9C2; pointer-events:none;\"></div>\n  <div style=\"position:absolute; inset:0; padding:0.85in 0.85in 0.62in;\">\n    <div style=\"display:flex; align-items:flex-end; justify-content:space-between; border-bottom:1.5px solid #2C2722; padding-bottom:10px; margin-bottom:30px;\">\n      <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:26px; margin:0;\">Contents</h2>\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; color:#B0492C; font-size:15px;\">Contents</span>\n    </div>\n    <div>\n      <div data-toc=\"vow\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Our Commitment</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"prayer\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Prayer Topics</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"travel\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Journey at a Glance (Flights & Lodging)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"overview\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Schedule Overview</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"grid\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Full Ministry Schedule</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"schedule\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Daily Schedule (by Day)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"roster\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Participant Roster</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"checklist\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Mission Prep Checklist</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"contacts\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Lodging & Emergency Contacts</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"guide\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Guatemala Guide & Culture</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"weather\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Local Weather (6/30–7/6)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"culture\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Culture Tour · Antigua</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"spanish\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Essential Spanish Phrases</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"qt\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Devotional & Diary (Q.T)</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"songs\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">Worship Sheet Music</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n      <div data-toc=\"mk_program\" style=\"display:flex; align-items:baseline; gap:10px; padding:12px 0; border-bottom:1px dotted #CFC2A8;\"><span style=\"font-family:'Gowun Batang',serif; font-size:17px;\">MK Program & Profiles</span><span style=\"flex:1;\"></span><span data-toc-no style=\"font-family:'EB Garamond',serif; color:#B0492C; font-size:15px;\"></span></div>\n    </div>"
