    "label": "Schedule 7/1-7/2",
    "section": "schedule",
    "html": "<div style=\"position:absolute; inset:0.42in; border:1px solid #E4D9C2; pointer-events:none;\"></div>\n  <div style=\"position:absolute; inset:0; padding:0.85in 0.85in 0.62in;\">\n    <div style=\"display:flex; align-items:flex-end; justify-content:space-between; border-bottom:1.5px solid #2C2722; padding-bottom:10px; margin-bottom:22px;\">\n      <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:26px; margin:0;\">Daily Schedule</h2>\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; color:#B0492C; font-size:15px;\">Daily Schedule</span>\n    </div>\n\n    <div style=\"display:flex; align-items:baseline; gap:12px; margin-bottom:10px;\">\n      <span style=\"font-family:'Gowun Batang',serif; font-size:19px; color:#B0492C;\">Day 1</span>\n      <span style=\"font-size:14px; color:#6E6556;\">7/1 (Wed) · Hotel Barceló</span>\n    </div>\n    <table style=\"width:100%; border-collapse:collapse; font-size:12.5px; margin-bottom:24px;\">\n      <tbody>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; width:128px; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">07:00 — 08:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Ministry Prep</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">13:00 —</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Registration & check-in · Beauty/Medical ①</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">17:00 — 18:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Rest</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">18:00 — 19:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Dinner</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">19:00 — 19:55</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\"><strong style=\"font-weight:500;\">Opening Worship</strong> — Pastor 박승진, &ldquo;Abide in Me&rdquo; <span style=\"color:#6E6556;\">(John 15:1–9)</span></td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">20:00 — 21:15</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\"><strong style=\"font-weight:500;\">Welcome Night</strong> — relay dance · skit · La Gloria de Dios · choir</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">21:00 —</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Rest & Sleep</td></tr>\n      </tbody>\n    </table>\n\n    <div style=\"display:flex; align-items:baseline; gap:12px; margin-bottom:10px;\">\n      <span style=\"font-family:'Gowun Batang',serif; font-size:19px; color:#B0492C;\">Day 2</span>\n      <span style=\"font-size:14px; color:#6E6556;\">7/2 (Thu) · Seminars & Night of Blessing</span>\n    </div>\n    <table style=\"width:100%; border-collapse:collapse; font-size:12.5px;\">\n      <tbody>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; width:128px; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">07:00 — 08:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Wake-up & Breakfast</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">08:00 — 09:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Beauty/Medical ②</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">09:40 — 12:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\"><strong style=\"font-weight:500;\">Morning Seminar</strong> — Pastor 이동원, &ldquo;Lord of All & Lord of Faith / Lord of Life & Lord of Mission&rdquo;</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">12:00 — 13:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Lunch</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">13:00 — 17:00</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Beauty/Medical ③④ · Afternoon Seminar (Pastor 김우준)</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">18:00 — 19:30</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Dinner</td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">19:30 — 21:10</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\"><strong style=\"font-weight:500;\">Night of Blessing</strong> — Pastor 이동원, &ldquo;A Community of Celebration&rdquo; <span style=\"color:#6E6556;\">(John 2:1–11)</span></td></tr>\n        <tr><td style=\"border:1px solid #DCCFB8; padding:7px 10px; background:#F0E7D5; font-family:'EB Garamond',serif; color:#3A332B; white-space:nowrap;\">21:00 —</td><td style=\"border:1px solid #DCCFB8; padding:7px 12px; background:#fff;\">Rest & Sleep</td></tr>\n      </tbody>\n    </table>"
