    "label": "Participant Roster",
    "section": "roster",
    "html": "<div style=\"position:absolute; inset:0.42in; border:1px solid #E4D9C2; pointer-events:none;\"></div>\n  <div style=\"position:absolute; inset:0; padding:0.85in 0.85in 0.62in;\">\n    <div style=\"display:flex; align-items:flex-end; justify-content:space-between; border-bottom:1.5px solid #2C2722; padding-bottom:10px; margin-bottom:8px;\">\n      <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:26px; margin:0;\">Participant Roster</h2>\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; color:#B0492C; font-size:15px;\">Washington Team · 35</span>\n    </div>\n    <p style=\"margin:0 0 16px; font-size:12.5px; color:#6E6556;\">Washington Global Mission Church · roster by team &nbsp;·&nbsp; <span style=\"color:#B0492C;\">★</span> Leader</p>\n    <div style=\"columns:2; column-gap:34px;\">\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">Speakers & Staff</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>박승진 <span style=\"color:#9A8E78; font-size:11px;\">Speaker</span></li>\n          <li>박성현 <span style=\"color:#9A8E78; font-size:11px;\">Accompanying Pastor</span></li>\n          <li>이영진 <span style=\"color:#B0492C; font-size:11px;\">★ Overall Leader</span></li>\n        </ul>\n      </div>\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">Korean Medicine</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>정하늘 <span style=\"color:#B0492C; font-size:11px;\">★</span></li>\n          <li>조맹숙</li><li>조철민</li><li>황은경</li><li>김학숙</li><li>이종선</li><li>송병재</li><li>송인숙</li>\n        </ul>\n      </div>\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">Hair & Beauty</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>이경호 <span style=\"color:#B0492C; font-size:11px;\">★</span></li>\n          <li>이경미</li><li>임종수</li><li>임진숙</li><li>김정화</li><li>정복순</li>\n        </ul>\n      </div>\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">Facial</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>김혜경 <span style=\"color:#B0492C; font-size:11px;\">★</span></li>\n          <li>김미혜</li><li>박호선</li><li>이순복</li>\n        </ul>\n      </div>\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">MK</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>Daniel Cho <span style=\"color:#B0492C; font-size:11px;\">★ MK Leader</span></li>\n          <li>Timothy Lee</li><li>Esther Park</li><li>David Park</li><li>Tai Osunsan</li><li>Liora Lee</li><li>Jin Bak</li><li>Alex Suh</li><li>Daniel Seo</li><li>Daniel Kim</li><li>Danielle Lee</li><li>Hahnbit Kang</li>\n        </ul>\n      </div>\n      <div style=\"break-inside:avoid; margin-bottom:18px;\">\n        <h3 style=\"font-family:'Gowun Batang',serif; font-size:15px; color:#B0492C; margin:0 0 8px; padding-bottom:5px; border-bottom:1.5px solid #E0D4BC;\">MK (Participating)</h3>\n        <ul style=\"list-style:none; margin:0; padding:0; font-size:13.5px; line-height:2;\">\n          <li>Sarah Jung</li><li>Leah Jung</li>\n        </ul>\n      </div>\n    </div>"
