    "html": "<div style=\"position:absolute; inset:0.42in; border:1px solid #E4D9C2; pointer-events:none;\"></div>\n  <div style=\"position:absolute; inset:0; display:flex; flex-direction:column; align-items:center; justify-content:center; text-align:center;\">\n    <div style=\"display:flex; gap:8px; margin-bottom:28px;\">\n      <span style=\"width:12px; height:12px; transform:rotate(45deg); background:#B0492C; display:block;\"></span>\n      <span style=\"width:12px; height:12px; transform:rotate(45deg); background:#C18A33; display:block;\"></span>\n      <span style=\"width:12px; height:12px; transform:rotate(45deg); background:#74835F; display:block;\"></span>\n    </div>\n    <p style=\"font-family:'EB Garamond',serif; font-style:italic; font-size:18px; color:#B0492C; margin:0 0 12px;\">Worship</p>\n    <h2 style=\"font-family:'Gowun Batang',serif; font-weight:700; font-size:38px; margin:0;\">Worship Sheet Music</h2>\n    <div style=\"width:50px; height:2px; background:#C18A33; margin:24px 0 0;\"></div>"
