    "label": "Sheet {{ song.label }}",
    "section": "",
    "html": "<div style=\"position:absolute; inset:0; padding:0.6in 0.6in 0.7in; display:flex; flex-direction:column;\">\n    <div style=\"display:flex; align-items:center; justify-content:space-between; border-bottom:1px solid #DCCFB8; padding-bottom:7px; margin-bottom:12px;\">\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; font-size:12px; color:#B0492C; letter-spacing:1px;\">Worship · Sheet Music</span>\n      <span style=\"font-family:'EB Garamond',serif; font-size:12px; color:#A99B82;\">{{ song.label }}</span>\n    </div>\n    <div style=\"flex:1; display:flex; flex-direction:column; gap:12px; min-height:0;\">\n      <sc-for list=\"{{ song.srcs }}\" as=\"s\" hint-placeholder-count=\"1\">\n      <div style=\"flex:1; position:relative; min-height:0;\">\n        <img src=\"{{ s }}\" alt=\"Worship Sheet Music\" style=\"position:absolute; inset:0; width:100%; height:100%; object-fit:contain; object-position:top;\"/>\n      </div>\n      </sc-for>\n    </div>"
