    "html": "<div style=\"position:absolute; inset:0; padding:0.6in 0.6in 0.7in; display:flex; flex-direction:column;\">\n    <div style=\"display:flex; align-items:center; justify-content:space-between; border-bottom:1px solid #DCCFB8; padding-bottom:7px; margin-bottom:12px;\">\n      <span style=\"font-family:'EB Garamond',serif; font-style:italic; font-size:12px; color:#B0492C; letter-spacing:1px;\">MK Profile · God’s children we embrace and pray for</span>\n      <span style=\"font-family:'EB Garamond',serif; font-size:12px; color:#A99B82;\">{{ mk.n }} / 33</span>\n    </div>\n    <div style=\"flex:1; position:relative;\">\n      <img src=\"{{ mk.src }}\" alt=\"MK Profile\" style=\"position:absolute; inset:0; width:100%; height:100%; object-fit:contain;\"/>\n    </div>"
